#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
const int N=155,Mod=1e8;inline void DN(int &x){x>=Mod?x-=Mod:0;}
int a[N],b[N],c[N],A[N][26],B[N][26],C[N][26],na,nb,nc,dp[N][N][N];bool vis[N][N][N];
inline void Get(int *a,int &p)
{
	p=0;char ch=getchar();while(ch<'a'||ch>'z')ch=getchar();
	while(ch<='z'&&ch>='a')a[++p]=ch-'a',ch=getchar();
}
inline void dfs(const int &pa,const int &pb,const int &pc)
{
	if(vis[pa][pb][pc])return;vis[pa][pb][pc]=true;dp[pa][pb][pc]=1;
	rep(0,25,i)if(~A[pa][i]&&~B[pb][i]&&~C[pc][i])
	{
		dfs(A[pa][i],B[pb][i],C[pc][i]);
		DN(dp[pa][pb][pc]+=dp[A[pa][i]][B[pb][i]][C[pc][i]]);
	}
}
int main()
{
	Get(a,na);Get(b,nb);Get(c,nc);
	memset(A[na],-1,sizeof(A[na]));
	memset(B[nb],-1,sizeof(B[nb]));
	memset(C[nc],-1,sizeof(C[nc]));
	drep(na,1,i){memcpy(A[i-1],A[i],sizeof(A[i]));A[i-1][a[i]]=i;}
	drep(nb,1,i){memcpy(B[i-1],B[i],sizeof(B[i]));B[i-1][b[i]]=i;}
	drep(nc,1,i){memcpy(C[i-1],C[i],sizeof(C[i]));C[i-1][c[i]]=i;}
	dfs(0,0,0);printf("%d\n",dp[0][0][0]-1);
}
